import { DailyHoursDto } from '../types';
import { DbEmployee, DbPayrollEntry } from './schema';

// Ugly manual db seed data — in a real app this would come from an external source or be generated via scripts, but hardcoding it here is simplest for this exercise.

/** Shorthand for building a DailyHoursDto inline. */
function h(mon: number, tue: number, wed: number, thu: number, fri: number, sat: number, sun: number): DailyHoursDto {
  return { mon, tue, wed, thu, fri, sat, sun };
}

